  ('optician-moex-00559', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '患者初步驗光值為-5.00DS/-0.75DC×180 利用紅、綠雙色視標進行驗光終點確認檢查；主述紅色背景的數 字較黑、較清楚，則度數應修正為下列何者？', '["-4.75DS/-0.75DC×180", "-5.00DS/-0.50DC×180", "-5.00DS/-1.00DC×180", "-5.25DS/-0.75DC×180"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00560', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於LogMAR（LogarithmoftheMinimumAngleofResolution）視力表施測預期結果的表現，下列何者錯誤？', '["健康的成年人最佳矯正視力可達比0logMAR好一至兩行，標準差（SD）0.1logMAR", "兩隻眼睛之間的視力值差異不應大於0.16logMAR", "健康的3歲兒童視力可達+0.30logMAR以上，等同Snellen20/60以上", "健康的4歲兒童視力可達+0.20logMAR以上，等同Snellen10/16以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00561', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '進行對數視力表檢查時（LogMARchart），受檢者0.6之前的全數正確，0.5錯1個，0.4錯1個，0.3對3 個，0.2對1個。則最終視力應紀錄為何？', '["0.52", "0.44", "0.36", "0.28"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00562', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '被檢者注視6m標準視標，檢查者距離被檢者50cm處使用視網膜鏡平行光檢查，並加入鏡片-3.00DS為 中和現象，則被檢者未矯正屈光時本身原來的遠點，距離被檢者幾cm處，下列何者為正確？', '["20cm", "22.2cm", "33.3cm", "40cm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00563', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列關於針孔視力（pinholeacuity）測試的敘述，何者錯誤？', '["當患者的矯正視力小於20/30時，可以用針孔測量視力", "針孔測試的原理，在於減少視覺的景深，增加患者的視力", "針孔視力比原有的矯正視力改善，表示患者有殘餘的屈光異常", "針孔視力比原有的矯正視力一樣或更差，表示患者有屈光以外異常，如視網膜或視覺傳導路徑異常"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00564', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列有關手指數檢查（fingercountingvisualfieldstest）在測試的過程中，檢查者不宜比出幾根手指頭？', '["一根", "二根", "三根", "四根"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00565', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者矯正度數為：+4.00DS/-2.00DC×085，其最大屈光力與最小屈光力主徑線（子午線）互相垂直。此 受檢者的散光為下列何種型態？', '["順規散光（with-the-ruleastigmatism）", "逆規散光（against-the-ruleastigmatism）", "斜軸散光（obliqueastigmatism）", "不規則散光（irregularastigmatism）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00566', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '某近視-5.00D的患者，其遠點位於眼前何處？', '["50cm", "25cm", "20cm", "10cm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00567', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '一鏡片可將遠處而來的光線發散，在鏡片前方形成一虛焦點，該鏡片屬於何種類型？', '["稜鏡", "正鏡片", "柱面鏡片", "負鏡片"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00568', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '看遠方時需要配戴-2.00DS/+4.00DC×090的眼鏡矯正，可以得到最佳視力。此受測者為下列何者？', '["複合性近視散光（compoundmyopicastigmatism）", "複合性遠視散光（compoundhyperopicastigmatism）", "混合性散光（mixedastigmatism）", "簡單性近視散光（simplemyopicastigmatism）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
